-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
CREATE OR REPLACE VIEW brain_serving.mv_metric_aov_day AS
SELECT
  brand_id,
  period,
  currency_code,
  channel,
  gross_revenue_minor,
  order_count,
